import { Rating } from 'primereact/rating';
import { resolveUrl } from '../utils';

function GiftCard({ item, isOwner, itemMenuOpen, onImageClick, onMenuToggle, onMenuClose, onEdit, onTogglePurchased, onMove, onDelete, onReserve, onUnreserve }) {
  return (
    <div className="item-card" style={{ position: 'relative' }}>
      {/* Три точки — верхний правый угол */}
      {isOwner && (
        <div style={{ position: 'absolute', top: '0', right: '0', zIndex: 10 }}>
          <button
            onClick={(e) => { e.stopPropagation(); onMenuToggle(item.id); }}
            style={{
              width: '38px',
              height: '31px',
              borderRadius: '0 14px 0 20px',
              background: 'white',
              border: 'none',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#333',
              fontSize: '18px'
            }}
          >
            <i className="pi pi-ellipsis-v"></i>
          </button>
          {itemMenuOpen === item.id && (
            <>
              <div className="menu-overlay" onClick={(e) => { e.stopPropagation(); onMenuClose(); }} />
              <div className="wishlist-menu" onClick={(e) => e.stopPropagation()}>
                <button className="wishlist-menu-item" onClick={() => onEdit(item)}>
                  <i className="pi pi-pencil"></i><span>Редактировать</span>
                </button>
                {!item.isReserved && (
                  <button className="wishlist-menu-item" onClick={() => onTogglePurchased(item)}>
                    <i className={item.isPurchased ? 'pi pi-undo' : 'pi pi-check'}></i>
                    <span>{item.isPurchased ? 'Отменить подарено' : 'Отметить подаренным'}</span>
                  </button>
                )}
                <button className="wishlist-menu-item" onClick={() => onMove(item)}>
                  <i className="pi pi-arrow-right-arrow-left"></i><span>Перенести</span>
                </button>
                <button className="wishlist-menu-item delete" onClick={() => onDelete(item.id)}>
                  <i className="pi pi-trash"></i><span>Удалить</span>
                </button>
              </div>
            </>
          )}
        </div>
      )}

      {/* Изображение */}
      <div className="item-card-image" onClick={() => onImageClick(item)} style={{ position: 'relative' }}>
        {item.isReserved && isOwner ? (
          <div className="item-card-no-image">
            <i className="pi pi-gift" style={{ fontSize: '48px', color: '#1e293b' }}></i>
          </div>
        ) : item.imageUrl ? (
          <img
            src={resolveUrl(item.imageUrl)}
            alt={item.title}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
            onError={(e) => { e.target.style.display = 'none'; }}
          />
        ) : (
          <div className="item-card-no-image">
            <i className="pi pi-gift" style={{ fontSize: '48px' }}></i>
          </div>
        )}
        {/* Рейтинг */}
        <div className="item-card-rating" style={{ position: 'absolute', bottom: '0px', right: '0px', padding: '5px 10px', background: 'white', borderRadius: '15px 0 0 0'}} onClick={(e) => e.stopPropagation()}>
          <Rating value={item.priority || 3} readOnly cancel={false} onIcon={<img src="/images/path-2.svg" alt="heart" width="20px" height="20px" />} offIcon={<img src="/images/ti-heart.svg" alt="heart" width="20px" height="20px" />} />
        </div>
      </div>

      {/* Цена */}
      {item.price && <div className="item-card-price" style={{ marginLeft: '10px'}}>{item.price} ₽</div>}

      {/* Название */}
      <div className="item-card-title" style={{ marginLeft: '10px'}}>{item.title}</div>

      {/* Статус забронировано для владельца */}
      {item.isReserved && isOwner && (
        <div style={{ width: '100%', padding: '8px 12px', background: '#F3F4F6', borderRadius: '6px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', marginTop: '8px' }}>
          <i className="pi pi-lock" style={{ fontSize: '16px', color: '#6B7280' }}></i>
          <span style={{ fontSize: '14px', fontWeight: '500', color: '#6B7280' }}>Забронировано</span>
        </div>
      )}

      {/* Статусы для не-владельца */}
      {!isOwner && (
        <>
          {item.isReserved && !item.reservedByMe && (
            <div className="item-card-status reserved">🔒 Забронировано</div>
          )}
          {item.isPurchased && (
            <div className="item-card-status purchased">✓ Подарено</div>
          )}
        </>
      )}

      {/* Кнопки действий */}
      <div className="item-card-actions">
        {!isOwner && (
          <>
            {item.reservedByMe ? (
              <button
                onClick={() => onUnreserve(item)}
                style={{ width: '199px', height: '35px', borderRadius: '8px', background: 'white', color: '#188700', border: '2px solid #188700', fontSize: '16px', fontWeight: '500', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', transition: 'all 0.2s' }}
                onMouseEnter={(e) => { e.currentTarget.style.background = '#F0FDF4'; }}
                onMouseLeave={(e) => { e.currentTarget.style.background = 'white'; }}
              >
                <i className="pi pi-times" style={{ fontSize: '18px', color: '#188700' }}></i>
                Отменить бронь
              </button>
            ) : !item.isReserved ? (
              <button
                onClick={() => onReserve(item)}
                style={{ width: '199px', height: '35px', borderRadius: '8px', background: '#188700', color: 'white', border: 'none', fontSize: '16px', fontWeight: '500', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', transition: 'background 0.2s' }}
                onMouseEnter={(e) => e.currentTarget.style.background = '#146600'}
                onMouseLeave={(e) => e.currentTarget.style.background = '#188700'}
              >
                <i className="pi pi-gift" style={{ fontSize: '18px', color: '#188700' }}></i>
                Забронировать
              </button>
            ) : (
              <button
                disabled
                style={{ width: '199px', height: '35px', borderRadius: '8px', background: '#cccccc', color: '#666666', border: 'none', fontSize: '16px', fontWeight: '500', cursor: 'not-allowed', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}
              >
                <i className="pi pi-lock" style={{ fontSize: '18px' }}></i>
                Забронировано
              </button>
            )}
          </>
        )}

      </div>
    </div>
  );
}

export default GiftCard;
